using UnityEngine;
using System;

// Simple event system using delegates and events
public class EventSystem : MonoBehaviour
{
    // Events are declared with delegates
    public delegate void GameEventHandler();
    public static event GameEventHandler OnGameStart;
    public static event GameEventHandler OnGameOver;

    // Events with parameters
    public delegate void ScoreEventHandler(int score);
    public static event ScoreEventHandler OnScoreChanged;

    public delegate void HealthEventHandler(int currentHealth, int maxHealth);
    public static event HealthEventHandler OnHealthChanged;

    public static event Action<string> OnMessage;  // Using built-in Action
    public static event Action<int, int> OnDamageDealt;  // Action with multiple parameters

    private void Start()
    {
        // Trigger events
        OnGameStart?.Invoke();
        OnScoreChanged?.Invoke(0);
        OnHealthChanged?.Invoke(100, 100);
        OnMessage?.Invoke("Game started!");
    }

    public static void TriggerDamage(int damage, int health)
    {
        OnDamageDealt?.Invoke(damage, health);
    }
}

// Listener class — subscribes to events
public class EventListener : MonoBehaviour
{
    private void OnEnable()
    {
        // Subscribe to events
        EventSystem.OnGameStart += HandleGameStart;
        EventSystem.OnGameOver += HandleGameOver;
        EventSystem.OnScoreChanged += HandleScoreChanged;
        EventSystem.OnHealthChanged += HandleHealthChanged;
        EventSystem.OnMessage += HandleMessage;
        EventSystem.OnDamageDealt += HandleDamage;
    }

    private void OnDisable()
    {
        // Unsubscribe to prevent memory leaks
        EventSystem.OnGameStart -= HandleGameStart;
        EventSystem.OnGameOver -= HandleGameOver;
        EventSystem.OnScoreChanged -= HandleScoreChanged;
        EventSystem.OnHealthChanged -= HandleHealthChanged;
        EventSystem.OnMessage -= HandleMessage;
        EventSystem.OnDamageDealt -= HandleDamage;
    }

    private void HandleGameStart()
    {
        Debug.Log("🎮 Event received: Game Started!");
    }

    private void HandleGameOver()
    {
        Debug.Log("💀 Event received: Game Over!");
    }

    private void HandleScoreChanged(int score)
    {
        Debug.Log("🏆 Event received: Score changed to " + score);
    }

    private void HandleHealthChanged(int current, int max)
    {
        Debug.Log("❤️ Event received: Health " + current + "/" + max);
    }

    private void HandleMessage(string message)
    {
        Debug.Log("📨 Event received: " + message);
    }

    private void HandleDamage(int damage, int health)
    {
        Debug.Log("⚔️ Event received: " + damage + " damage dealt! Health: " + health);
    }
}

// ScoreManager — triggers score events
public class ScoreManager : MonoBehaviour
{
    private int score = 0;

    public void AddScore(int points)
    {
        score += points;
        EventSystem.OnScoreChanged?.Invoke(score);
        EventSystem.OnMessage?.Invoke("Score: " + score);

        if (score >= 100)
        {
            EventSystem.OnGameOver?.Invoke();
        }
    }
}

public class EventSystemExample : MonoBehaviour
{
    public EventListener listener;
    public ScoreManager scoreManager;

    void Start()
    {
        Debug.Log("=== Event System Example ===");

        // Trigger events manually
        EventSystem.OnGameStart?.Invoke();

        // Simulate damage
        EventSystem.TriggerDamage(25, 75);

        // Add score
        if (scoreManager != null)
        {
            scoreManager.AddScore(10);
            scoreManager.AddScore(50);
            scoreManager.AddScore(50);  // Should trigger GameOver
        }
    }
}

